// Iteration 2: Mirror IREE default tiling through TransformDialectCodegen
// Distribution [1,16,56,32], inner [1,1,8,32], reduction [1,1,3]
module attributes { transform.with_named_sequence } {

  transform.named_sequence @conv2d_strategy(
      %variant_op: !transform.any_op) {

    // Match the convolution
    %conv = transform.structured.match ops{["linalg.conv_2d_nhwc_hwcf"]}
      in %variant_op : (!transform.any_op) -> !transform.any_op

    // Level 1: Distribution tile - cache blocking
    // N=1, OH=16, OW=56, OC=32 (matches default level 0)
    %tiled_l1, %forall = transform.structured.tile_using_forall %conv
      tile_sizes [1, 16, 56, 32]
      : (!transform.any_op) -> (!transform.any_op, !transform.any_op)

    // Level 2: Inner tile for vectorization
    // N=1, OH=1, OW=8, OC=32 (matches default level 1)
    %tiled_l2, %lp_n, %lp_h, %lp_w, %lp_c =
      transform.structured.tile_using_for %tiled_l1 [1, 1, 8, 32]
      : (!transform.any_op) -> (!transform.any_op,
          !transform.op<"scf.for">, !transform.op<"scf.for">,
          !transform.op<"scf.for">, !transform.op<"scf.for">)

    // Level 3: Reduction tile - KH=1, KW=1, IC=3 (full)
    %tiled_r, %lr0, %lr1, %lr2 =
      transform.structured.tile_using_for %tiled_l2 [0, 0, 0, 0, 1, 1, 3]
      : (!transform.any_op) -> (!transform.any_op,
          !transform.op<"scf.for">, !transform.op<"scf.for">,

